// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.ir;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.List;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.BindingSetAssignment;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingSymbol;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.BindingUniverse;
import org.junit.jupiter.api.Test;

class FiniteRelationTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void duplicateRowsArePreservedWhenRenderingValues() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSymbol drug = universe.symbol("drug");
		IRI med1000 = VF.createIRI("urn:med:1000");
		IRI med1001 = VF.createIRI("urn:med:1001");
		FiniteRelation relation = new FiniteRelation(List.of(drug), List.of(
				row(med1000),
				row(med1000),
				row(med1001)));

		BindingSetAssignment assignment = relation.toBindingSetAssignment();

		int rows = 0;
		for (BindingSet ignored : assignment.getBindingSets()) {
			rows++;
		}
		assertEquals(3, rows);
	}

	@Test
	void undefinedCellKeepsTupleArityButIsNotAssured() {
		BindingUniverse universe = BindingUniverse.create();
		BindingSymbol drug = universe.symbol("drug");
		FiniteRelation relation = new FiniteRelation(List.of(drug),
				List.of(new FiniteRelation.Row(List.of(FiniteRelation.Cell.unbound()))));

		assertTrue(relation.possibleMask(universe).contains(drug));
		assertFalse(relation.assuredMask(universe).contains(drug));
		assertEquals(1, relation.toBindingSetAssignment().getBindingNames().size());
	}

	private static FiniteRelation.Row row(IRI value) {
		return new FiniteRelation.Row(List.of(FiniteRelation.Cell.bound(value)));
	}
}
